function asText(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(asText).filter(Boolean).join(' ');
  return String(value);
}

function compact(value) {
  return asText(value).replace(/\r/g, '').replace(/\s+/g, ' ').trim();
}

function digits(value) {
  return asText(value).replace(/\D/g, '');
}

function lower(value) {
  return compact(value).toLowerCase();
}

function firstNonEmpty(...values) {
  for (const value of values) {
    const text = compact(value);
    if (text) return text;
  }
  return null;
}

function inferIntent(message, context) {
  const text = lower(message);
  const flow = lower(context.tipo_fluxo || context.flow_type || '');

  if (/humano|atendente|pessoa|suporte|falar com/.test(text)) return 'human_handoff';
  if (/link|boleto|pagamento|pix|2 via|segunda via|reenvia/.test(text)) return 'link_resend';
  if (/cancelar|cancelamento/.test(text)) return 'cancelar_agendamento';
  if (/reagendar|remarcar|trocar horario|trocar horário/.test(text)) return 'reagendar_agendamento';
  if (/documento|documentos|anexo|arquivo|rg|cnh|contrato/.test(text)) return 'enviar_documentos';
  if (/videoconferencia|videochamada|link da reuniao|link da reunião/.test(text)) return 'link_videoconferencia';
  if (/renovar|renovacao|renovação|quero seguir|continuar/.test(text) && flow !== 'agendamento') return 'seguir_renovacao';
  if (/agendamento|agendar|horario|horário|confirmar horario|confirmar horário/.test(text) || flow === 'agendamento') return 'seguir_agendamento';
  if (flow === 'renovacao') return 'seguir_renovacao';
  return 'human_handoff';
}

function inferRoute(intent, context) {
  if (intent === 'human_handoff') return 'human_handoff';
  if (intent === 'link_resend') return 'link_resend';
  if (['cancelar_agendamento', 'reagendar_agendamento', 'enviar_documentos', 'link_videoconferencia', 'seguir_agendamento'].includes(intent)) return 'agendamento';
  if (lower(context.tipo_fluxo || context.flow_type || '') === 'agendamento') return 'agendamento';
  if (lower(context.tipo_fluxo || context.flow_type || '') === 'renovacao') return 'renovacao';
  if (intent === 'seguir_renovacao') return 'renovacao';
  return 'human_handoff';
}

const raw = $json;
const context = raw.context || raw.payload?.context || raw.metadata?.context || {};
const messageText = firstNonEmpty(raw.message_text, raw.text, raw.body, raw.content, raw.message?.text, raw.last_message, raw.payload?.message_text) || '';
const customerPhone = firstNonEmpty(raw.customer_phone, raw.phone, raw.from, raw.remoteJid, raw.contact?.phone, raw.sender?.phone, context.customer_phone);
const customerEmail = firstNonEmpty(raw.customer_email, raw.email, raw.contact?.email, context.customer_email);
const customerName = firstNonEmpty(raw.customer_name, raw.name, raw.contact?.name, raw.sender?.name, context.customer_name, 'Cliente');
const conversationId = firstNonEmpty(raw.conversation_id, raw.chat_id, raw.ticket_id, raw.id, context.conversation_id);
const flowType = firstNonEmpty(context.tipo_fluxo, context.flow_type, context.tipo, raw.flow_type);
const intent = inferIntent(messageText, context);
const routeTarget = inferRoute(intent, { ...context, tipo_fluxo: flowType });
const urls = {
  renovacao: $env.N8N_CLARA_RENOVACAO_URL || 'http://localhost:5678/webhook/avmd-clara-renovacao',
  agendamento: $env.N8N_CLARA_AGENDAMENTO_URL || 'http://localhost:5678/webhook/avmd-clara-agendamento',
  link_resend: $env.N8N_CLARA_LINK_URL || 'http://localhost:5678/webhook/avmd-clara-link-resender',
  human_handoff: $env.N8N_CLARA_HUMAN_URL || 'http://localhost:5678/webhook/avmd-clara-human-handoff',
};

return [{
  json: {
    conversation_id: conversationId,
    customer_name: customerName,
    customer_phone: digits(customerPhone),
    customer_email: customerEmail,
    channel: compact(raw.channel || context.channel || 'whatsapp').toLowerCase(),
    message_text: messageText,
    message_id: firstNonEmpty(raw.message_id, raw.id, context.message_id),
    source: compact(raw.source || context.source || 'clara').toLowerCase(),
    intent,
    route_target: routeTarget,
    handler_url: urls[routeTarget],
    context: {
      ...context,
      tipo_fluxo: flowType || null,
    },
    raw,
  }
}];
